// Get workflow-level static cache
const staticData = $getWorkflowStaticData('global');

/**
 * 1️⃣ Convert business_config table rows into an object (dynamic, no hardcoding)
 * Table shape assumed:
 * | key | value |
 */
const businessConfigObject = {};

for (const item of $items("Fetch Business Configuration")) {
  businessConfigObject[item.json.key] = item.json.value;
}

/**
 * 2️⃣ Group services by category
 * Table shape assumed:
 * | service_id | service_name | category | active |
 */
const servicesByCategory = {};

for (const item of $items("Fetch Services")) {
  if (item.json.active !== true) continue;

  const category = item.json.category;
  const serviceName = item.json.service_name;

  if (!servicesByCategory[category]) {
    servicesByCategory[category] = [];
  }

  servicesByCategory[category].push(serviceName);
}

/**
 * 3️⃣ Convert grouped services into desired format
 * [
 *   { category: "...", service: "A, B, C" }
 * ]
 */
const groupedServices = Object.entries(servicesByCategory).map(
  ([category, services]) => ({
    category,
    service: services.join(", ")
  })
);

/**
 * 4️⃣ Store everything dynamically in static cache
 */
staticData.business_data = {
  business_config: businessConfigObject,
  services: groupedServices,
  updated_at: new Date().toISOString()
};

/**
 * 5️⃣ Return confirmation output only
 */
return [
  {
    json: {
      cached: true,
      config_keys: Object.keys(businessConfigObject),
      categories_count: groupedServices.length,
      services_count: groupedServices.reduce(
        (sum, c) => sum + c.service.split(",").length,
        0
      ),
      updated_at: staticData.business_data.updated_at
    }
  }
];

const messages = $input.first().json.data
  .filter(i => i.message_text) // ignore nulls
  .sort((a, b) => new Date(a.created_at) - new Date(b.created_at))
  .map(i => ({
    role: i.direction === 'IN' ? 'user' : 'assistant',
    content: i.message_text
  }));

return [
  {
    json: {
      conversation_history: messages,
      phone: $input.first().json.data[0].phone
    }
  }
];

const messages = $input.first().json.data.map(item => item.message_text);

// Merge into one user turn
const mergedUserMessage = messages
  .map(text => (text || '').trim())
  .filter(Boolean)
  .join(' \n ');

// Return as single item
return [
  {
    json: {
      user_message: mergedUserMessage
    }
  }
];
